                        ctx.fillRect(plat.x, plat.y, plat.w, plat.h);
                        ctx.fillStyle = '#7a5a5a';
                        ctx.fillRect(plat.x + 5, plat.y + 5, plat.w - 10, plat.h - 10);
                        break;
                }
            }

            // Draw goal marker (end of level)
            ctx.fillStyle = '#ffd700';
            ctx.beginPath();
            ctx.moveTo(3100, 420);
            ctx.lineTo(3120, 380);
            ctx.lineTo(3140, 420);
            ctx.fill();
            ctx.fillStyle = '#fff';
