            ctx.beginPath();
            ctx.arc(player.x, player.y, player.radius, 0, Math.PI * 2);
            ctx.fillStyle = player.color;
            ctx.fill();
            ctx.strokeStyle = '#fff';
            ctx.lineWidth = 2;
            ctx.stroke();

            // Player "face" direction indicator
            ctx.beginPath();
            ctx.arc(player.x + (player.vx >= 0 ? 5 : -5), player.y - 3, 4, 0, Math.PI * 2);
            ctx.fillStyle = '#fff';
            ctx.fill();

