            if(!player.grounded) {
                ctx.strokeStyle = 'rgba(0, 212, 255, 0.4)';
                ctx.setLineDash([5, 5]);
                ctx.beginPath();
                ctx.moveTo(player.x, player.y);
                let px = player.x, py = player.y, pvx = player.vx, pvy = player.vy;
                for(let i = 0; i < 20; i++) {
