            // UI Overlay
            if(game.paused) {
                ctx.fillStyle = 'rgba(0,0,0,0.7)';
                ctx.fillRect(0, 0, canvas.width, canvas.height);
                ctx.fillStyle = '#fff';
                ctx.font = 'bold 24px sans-serif';
                ctx.textAlign = 'center';
                ctx.fillText('⏸ PAUSED', canvas.width/2, canvas.height/2);
                ctx.font = '14px sans-serif';
                ctx.fillText('Press P to continue', canvas.width/2, canvas.height/2 + 30);
                ctx.textAlign = 'start';
            }

            // HUD
            ctx.fillStyle = '#00d4ff';
            ctx.font = 'bold 12px monospace';
            ctx.fillText(`POS: ${Math.floor(player.x)},${Math.floor(player.y)}`, 10, 20);
            ctx.fillText(`VEL: ${player.vx.toFixed(1)},${player.vy.toFixed(1)}`, 10, 35);
        }

        // Game loop
        function loop() {
            update();
            draw();
            requestAnimationFrame(loop);
        }

        // Start
        console.log('🎮 Level Prototype Loaded');
        console.log('Sections: A=Intro, B=Snake Path, C=Combat, D=Hub');
        loop();
    </script>
</body>
</html>
