            ctx.fillText(`GROUNDED: ${player.grounded}`, 10, 50);
            ctx.fillText(`FPS: ~60 (requestAnimationFrame)`, 10, 65);
        }

        // ==========================================
        // GAME LOOP
        // ==========================================
        function loop() {
            update();
            render();
            requestAnimationFrame(loop);
        }

